from urllib.parse import urlparse, urljoin
from flask import request, redirect, url_for

def is_safe_url(target):
    """
    Check if the target URL is safe for redirection.
    Prevents open redirect vulnerabilities by ensuring the URL is relative
    or belongs to the same host.
    """
    if not target:
        return False
    
    # Parse the target URL
    ref_url = urlparse(request.host_url)
    test_url = urlparse(urljoin(request.host_url, target))
    
    # Check if the scheme and netloc match (same domain)
    # Also allow relative URLs (empty netloc)
    return (test_url.scheme in ('http', 'https') and 
            ref_url.netloc == test_url.netloc) or \
           (not test_url.netloc and not test_url.scheme)


def get_redirect_target():
    """
    Get the redirect target from request parameters or referrer.
    Returns None if no valid target is found.
    """
    # Check common parameter names for redirect URLs
    for target in [request.args.get('next'), 
                   request.args.get('redirect'),
                   request.form.get('next'),
                   request.form.get('redirect')]:
        if target and is_safe_url(target):
            return target
    return None


def redirect_to_intended_destination(default_endpoint='dashboard', **kwargs):
    """
    Redirect user to their intended destination after authentication.
    Falls back to default endpoint if no safe redirect target is found.
    
    Args:
        default_endpoint: The default route to redirect to if no safe target exists
        **kwargs: Additional arguments to pass to url_for for the default endpoint
    
    Returns:
        Flask redirect response
    """
    target = get_redirect_target()
    
    if target:
        return redirect(target)
    
    # Fallback to default endpoint
    return redirect(url_for(default_endpoint, **kwargs))


def login_redirect(user, default_endpoint='dashboard', **kwargs):
    """
    Complete login redirect function that handles user authentication
    and redirects to intended destination.
    
    Args:
        user: The authenticated user object
        default_endpoint: Default route if no redirect target
        **kwargs: Additional arguments for url_for
    
    Returns:
        Flask redirect response
    """
    # Perform any post-login operations here
    # e.g., login_user(user) if using Flask-Login
    
    return redirect_to_intended_destination(default_endpoint, **kwargs)


# Alternative standalone function without Flask dependency
def is_safe_redirect_url(target_url, allowed_hosts=None):
    """
    Standalone function to check if a redirect URL is safe.
    
    Args:
        target_url: The URL to validate
        allowed_hosts: List of allowed hostnames (optional)
    
    Returns:
        Boolean indicating if the URL is safe
    """
    if not target_url:
        return False
    
    # Remove whitespace and check for common attack patterns
    target_url = target_url.strip()
    
    # Block javascript: and data: schemes
    if target_url.lower().startswith(('javascript:', 'data:', 'vbscript:')):
        return False
    
    # Parse the URL
    parsed = urlparse(target_url)
    
    # Allow relative URLs (no scheme or netloc)
    if not parsed.netloc and not parsed.scheme:
        return True
    
    # If scheme exists, it must be http or https
    if parsed.scheme and parsed.scheme not in ('http', 'https'):
        return False
    
    # If allowed_hosts is specified, check against it
    if allowed_hosts:
        return parsed.netloc in allowed_hosts
    
    # If no allowed_hosts specified, only allow relative URLs
    return not parsed.netloc


def safe_redirect(target_url, default_url='/', allowed_hosts=None):
    """
    Safely redirect to target URL or default if target is unsafe.
    
    Args:
        target_url: The intended redirect destination
        default_url: Fallback URL if target is unsafe
        allowed_hosts: List of allowed hostnames
    
    Returns:
        Safe URL for redirection
    """
    if is_safe_redirect_url(target_url, allowed_hosts):
        return target_url
    return default_url